function throttle(func, limitMs) {
  let lastExecuted = 0; // Stored in closure

  return function(...args) {
    const now = Date.now();
    if (now - lastExecuted >= limitMs) {
      func.apply(this, args); // Execute original function
      lastExecuted = now;     // Update the timestamp
    }
  };
}

// Original heavy function
function calculateScrollParallax() {
  console.log('Doing heavy math for parallax at:', window.scrollY);
}

// Create throttled version (max 1 execution per 200ms)
const throttledScroll = throttle(calculateScrollParallax, 200);

